{"content": "     1|import { Hono } from "hono";
     2|import { SPEC_VERSION, type SnapFunction } from "@farcaster/snap";
     3|import { registerSnapHandler } from "@farcaster/snap-hono";
     4|import {
     5|  createInMemoryDataStore,
     6|  createTursoDataStore,
     7|} from "@farcaster/snap-turso";
     8|
     9|// ─── Config ───────────────────────────────────────────────────────
    10|const HUB_BASE = "https://snapchain-api.neynar.com/v1";
    11|const REST_BASE = "https://api.neynar.com/v2/farcaster";
    12|const NEYNAR_KEY = process.env.NEYNAR_API_KEY ?? "";
    13|const DAILY_SWIPE_LIMIT = 3;
    14|const MIN_ACCOUNT_AGE_DAYS = 180;
    15|const MIN_NEYNAR_SCORE = 0.42;
    16|const MIN_FOLLOWER_RATIO = 0.15;
    17|const MIN_FOLLOWERS = 10;
    18|const MAX_POOL_SIZE = 60;
    19|const RESET_HOUR_UTC = 0;
    20|const SPEC = SPEC_VERSION;
    21|
    22|if (!NEYNAR_KEY) {
    23|  console.error("⚠️  NEYNAR_API_KEY not set!");
    24|}
    25|
    26|// ─── Data Store ───────────────────────────────────────────────────
    27|const store =
    28|  process.env.VERCEL === "1"
    29|    ? createTursoDataStore()
    30|    : createInMemoryDataStore();
    31|
    32|// ─── Types ────────────────────────────────────────────────────────
    33|interface NeynarUser {
    34|  fid: number;
    35|  username: string;
    36|  display_name: string;
    37|  pfp_url: string;
    38|  profile: { bio: { text: string } };
    39|  follower_count: number;
    40|  following_count: number;
    41|  power_badge: boolean;
    42|  score: number;
    43|  verifications: string[];
    44|  registered_at: string;
    45|}
    46|
    47|interface Profile {
    48|  fid: number;
    49|  username: string;
    50|  displayName: string;
    51|  pfpUrl: string;
    52|  bio: string;
    53|  followers: number;
    54|  following: number;
    55|}
    56|
    57|interface CastMessage {
    58|  data: {
    59|    type: string;
    60|    fid: number;
    61|    timestamp: number;
    62|    castAddBody: {
    63|      text: string;
    64|      mentions: number[];
    65|      parentCastId?: { fid: number; hash: string };
    66|      parentUrl?: string | null;
    67|      embeds: any[];
    68|    };
    69|  };
    70|  hash: string;
    71|}
    72|
    73|// ─── Hub API (FREE — snapchain) ───────────────────────────────────
    74|async function hubFetch<T>(path: string): Promise<T | null> {
    75|  if (!NEYNAR_KEY) return null;
    76|  try {
    77|    const res = await fetch(`${HUB_BASE}${path}`, {
    78|      headers: { "x-api-key": NEYNAR_KEY },
    79|    });
    80|    if (!res.ok) {
    81|      console.error(`Hub ${path}: ${res.status}`);
    82|      return null;
    83|    }
    84|    return (await res.json()) as T;
    85|  } catch (e) {
    86|    console.error(`Hub error ${path}:`, e);
    87|    return null;
    88|  }
    89|}
    90|
    91|// ─── REST API (user/bulk is free tier) ────────────────────────────
    92|async function restFetch<T>(path: string): Promise<T | null> {
    93|  if (!NEYNAR_KEY) return null;
    94|  try {
    95|    const res = await fetch(`${REST_BASE}${path}`, {
    96|      headers: { api_key: NEYNAR_KEY },
    97|    });
    98|    if (!res.ok) {
    99|      console.error(`REST ${path}: ${res.status}`);
   100|      return null;
   101|    }
   102|    return (await res.json()) as T;
   103|  } catch (e) {
   104|    console.error(`REST error ${path}:`, e);
   105|    return null;
   106|  }
   107|}
   108|
   109|async function fetchUsers(fids: number[]): Promise<NeynarUser[]> {
   110|  if (fids.length === 0) return [];
   111|  const data = await restFetch<{ users: NeynarUser[] }>(
   112|    `/user/bulk?fids=${fids.join(",")}`
   113|  );
   114|  return data?.users ?? [];
   115|}
   116|
   117|async function fetchCastsByFid(fid: number, limit = 50): Promise<CastMessage[]> {
   118|  const data = await hubFetch<{ messages: CastMessage[] }>(
   119|    `/castsByFid?fid=${fid}&pageSize=${limit}`
   120|  );
   121|  return data?.messages ?? [];
   122|}
   123|
   124|async function discoverFidsViaHub(seedFids: number[], maxDiscover = 100): Promise<number[]> {
   125|  const discovered = new Set<number>();
   126|  const sampleSeeds = shuffleArray(seedFids).slice(0, 5);
   127|  for (const seedFid of sampleSeeds) {
   128|    const casts = await fetchCastsByFid(seedFid, 20);
   129|    for (const cast of casts) {
   130|      const mentions = cast.data.castAddBody?.mentions ?? [];
   131|      for (const mid of mentions) {
   132|        if (mid !== seedFid) discovered.add(mid);
   133|      }
   134|      const parentFid = cast.data.castAddBody?.parentCastId?.fid;
   135|      if (parentFid && parentFid !== seedFid) discovered.add(parentFid);
   136|      if (discovered.size >= maxDiscover) break;
   137|    }
   138|    if (discovered.size >= maxDiscover) break;
   139|  }
   140|  return Array.from(discovered);
   141|}
   142|
   143|// ─── Qualification ─────────────────────────────────────────────────
   144|function qualifyUser(user: NeynarUser) {
   145|  const accountAgeDays = daysSince(user.registered_at);
   146|  const neynarScore = user.score ?? 0;
   147|  const followerRatio =
   148|    user.following_count > 0
   149|      ? user.follower_count / user.following_count
   150|      : user.follower_count > 0 ? 999 : 0;
   151|
   152|  if (accountAgeDays < MIN_ACCOUNT_AGE_DAYS) return { qualified: false, reason: "Account too new" };
   153|  if (neynarScore < MIN_NEYNAR_SCORE) return { qualified: false, reason: "Score too low" };
   154|  if (followerRatio < MIN_FOLLOWER_RATIO) return { qualified: false, reason: "Follower ratio too low" };
   155|  if (user.follower_count < MIN_FOLLOWERS) return { qualified: false, reason: "Too few followers" };
   156|  return { qualified: true, reason: "OK" };
   157|}
   158|
   159|// ─── Helpers ──────────────────────────────────────────────────────
   160|const VALID_IMG_EXT = /\.(jpg|jpeg|png|gif|webp)(\?.*)?$/i;
   161|
   162|// Check if a URL has a valid image extension (what the Farcaster client accepts)
   163|function hasValidImageExt(url: string): boolean {
   164|  const clean = url.split("?")[0].split("#")[0];
   165|  return VALID_IMG_EXT.test(clean);
   166|}
   167|
   168|// Best-effort image URL that the Farcaster client will render
   169|// Neynar's imagedelivery.net URLs lack file extensions — client rejects them
   170|// Generate personalized placeholder from username when real URL is invalid
   171|function safeImageUrl(url: string | undefined | null, username?: string): string {
   172|  if (url && hasValidImageExt(url)) return url;
   173|  // Generate a personalized placeholder with the user's initials
   174|  const initials = (username ?? "??").slice(0, 2).toUpperCase();
   175|  return `https://dummyimage.com/200x200/1A1528/C4A7E7.png?text=${encodeURIComponent(initials)}`;
   176|}
   177|
   178|function daysSince(dateStr: string): number {
   179|  return Math.floor((Date.now() - new Date(dateStr).getTime()) / (1000 * 60 * 60 * 24));
   180|}
   181|
   182|function todayKey(): string {
   183|  const now = new Date();
   184|  if (now.getUTCHours() < RESET_HOUR_UTC) now.setUTCDate(now.getUTCDate() - 1);
   185|  return now.toISOString().slice(0, 10);
   186|}
   187|
   188|function clamp(s: string, max: number): string {
   189|  return s.length <= max ? s : s.slice(0, max - 3) + "...";
   190|}
   191|
   192|function shuffleArray<T>(arr: T[]): T[] {
   193|  const a = [...arr];
   194|  for (let i = a.length - 1; i > 0; i--) {
   195|    const j = Math.floor(Math.random() * (i + 1));
   196|    [a[i], a[j]] = [a[j], a[i]];
   197|  }
   198|  return a;
   199|}
   200|
   201|function snapBase(request: Request): string {
   202|  const fromEnv = process.env.SNAP_PUBLIC_BASE_URL?.trim();
   203|  if (fromEnv) return fromEnv.replace(/\/$/, "");
   204|  const host = request.headers.get("x-forwarded-host")?.split(",")[0].trim()
   205|    ?? request.headers.get("host")?.split(",")[0].trim();
   206|  const isLoopback = host && /^(localhost|127\.0\.0\.1|\[::1\]|::1)(:\d+)?$/.test(host);
   207|  const proto = request.headers.get("x-forwarded-proto")?.split(",")[0].trim().toLowerCase()
   208|    ?? (isLoopback ? "http" : "https");
   209|  if (host) return `${proto}://${host}`.replace(/\/$/, "");
   210|  return `http://localhost:${process.env.PORT ?? "3003"}`.replace(/\/$/, "");
   211|}
   212|
   213|// ─── Turso Helpers ────────────────────────────────────────────────
   214|async function getBehavioralTag(fid: number): Promise<string | null> {
   215|  return ((await store.get(`bt:${fid}`)) as any)?.tag ?? null;
   216|}
   217|async function setBehavioralTag(fid: number, tag: string) {
   218|  await store.set(`bt:${fid}`, { tag, timestamp: Date.now() });
   219|}
   220|async function getQualification(fid: number) {
   221|  return ((await store.get(`qual:${fid}`)) as any) ?? null;
   222|}
   223|async function setQualification(fid: number, result: any) {
   224|  await store.set(`qual:${fid}`, { ...result, checkedAt: Date.now() });
   225|}
   226|async function getSwipeCount(fid: number): Promise<number> {
   227|  return ((await store.get(`sc:${fid}:${todayKey()}`)) as any)?.count ?? 0;
   228|}
   229|async function incrementSwipe(fid: number): Promise<number> {
   230|  const key = `sc:${fid}:${todayKey()}`;
   231|  const count = (((await store.get(key)) as any)?.count ?? 0) + 1;
   232|  await store.set(key, { count });
   233|  return count;
   234|}
   235|async function recordSwipe(swiperFid: number, targetFid: number, direction: string, tag: string) {
   236|  const data = (await store.get(`swipes:${swiperFid}`)) as any;
   237|  const swipes: any[] = data?.swipes ?? [];
   238|  swipes.push({ targetFid, direction, tag, ts: Date.now() });
   239|  await store.set(`swipes:${swiperFid}`, { swipes });
   240|}
   241|async function getSwipedFids(fid: number): Promise<Set<number>> {
   242|  return new Set((((await store.get(`swipes:${fid}`)) as any)?.swipes ?? []).map((s: any) => s.targetFid));
   243|}
   244|async function getProfilePool(fid: number): Promise<Profile[]> {
   245|  return (((await store.get(`pool:${fid}`)) as any)?.profiles ?? []) as Profile[];
   246|}
   247|async function setProfilePool(fid: number, profiles: Profile[]) {
   248|  await store.set(`pool:${fid}`, { profiles: profiles.map(p => ({ ...p })), builtAt: Date.now() });
   249|}
   250|
   251|// ─── Seed FIDs ────────────────────────────────────────────────────
   252|const SEED_FIDS: number[] = [
   253|  3, 56, 185, 194, 226, 239, 276, 341, 576, 756,
   254|  859, 930, 1114, 1158, 1215, 1311, 1600, 1689, 1899, 2048,
   255|  2309, 2411, 2515, 2608, 2714, 2858, 2934, 3098, 3201, 3354,
   256|  3456, 3600, 3757, 3890, 3988, 4123, 4267, 4400, 4501, 4678,
   257|  4801, 4923, 5056, 5189, 5300, 5423, 5567, 5700, 5834, 5978,
   258|  6100, 6234, 6367, 6500, 6634, 6778, 6900, 7034, 7167, 7300,
   259|  7434, 7567, 7700, 7834, 7967, 8100, 8234, 8367, 8500, 8634,
   260|  8767, 8900, 9034, 9167, 9300, 9434, 9567, 9700, 9834, 9967,
   261|];
   262|
   263|// ─── Pool Builder ─────────────────────────────────────────────────
   264|async function buildProfilePool(swiperFid: number): Promise<Profile[]> {
   265|  const swiped = await getSwipedFids(swiperFid);
   266|  const hubDiscovered = await discoverFidsViaHub(SEED_FIDS, 80);
   267|  const allFids = new Set([...SEED_FIDS, ...hubDiscovered]);
   268|  allFids.delete(swiperFid);
   269|  for (const fid of swiped) allFids.delete(fid);
   270|  const candidates = shuffleArray(Array.from(allFids)).slice(0, 50);
   271|  if (candidates.length === 0) return [];
   272|
   273|  const qualified: Profile[] = [];
   274|  for (let i = 0; i < candidates.length && qualified.length < MAX_POOL_SIZE; i += 20) {
   275|    const batch = candidates.slice(i, i + 20);
   276|    const users = await fetchUsers(batch);
   277|    for (const user of users) {
   278|      if (qualified.length >= MAX_POOL_SIZE) break;
   279|      if (qualifyUser(user).qualified) {
   280|        qualified.push({
   281|          fid: user.fid, username: user.username, displayName: user.display_name,
   282|          pfpUrl: user.pfp_url, bio: clamp(user.profile?.bio?.text ?? "", 160),
   283|          followers: user.follower_count, following: user.following_count,
   284|        });
   285|      }
   286|    }
   287|  }
   288|  return qualified;
   289|}
   290|
   291|// ─── Dark Fallback HTML ───────────────────────────────────────────
   292|const DARK_HTML = `<!DOCTYPE html>
   293|<html lang="en"><head>
   294|<meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
   295|<title>Pass? or Yass? 🧐</title>
   296|<style>
   297|*{margin:0;padding:0;box-sizing:border-box}
   298|body{font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,sans-serif;background:#0D0B14;min-height:100vh;display:flex;align-items:center;justify-content:center;flex-direction:column;padding:24px;color:#E0DEF4}
   299|.card{background:linear-gradient(145deg,#1A1528,#1E1433,#16102B);border:1px solid #2D2248;border-radius:16px;max-width:420px;width:100%;padding:24px;box-shadow:0 8px 32px rgba(100,60,180,.15),0 0 60px rgba(140,100,220,.05)}
   300|.title{font-size:22px;font-weight:700;text-align:center;color:#C4A7E7;margin-bottom:8px}
   301|.sub{font-size:14px;text-align:center;color:#908CAA;margin-bottom:24px}
   302|.btns{display:flex;gap:12px}
   303|.b{flex:1;padding:12px 16px;border-radius:10px;font-size:14px;font-weight:600;cursor:pointer;font-family:inherit;text-align:center;text-decoration:none}
   304|.bp{background:transparent;color:#908CAA;border:2px solid #393552}
   305|.bp:hover{border-color:#EB6F92;color:#EB6F92}
   306|.by{background:linear-gradient(135deg,#907AA9,#C4A7E7);color:#fff;border:none}
   307|.by:hover{filter:brightness(1.1)}
   308|.ft{margin-top:20px;text-align:center}
   309|.ft a{color:#6E6A86;text-decoration:none;font-size:13px}
   310|.ft a:hover{color:#C4A7E7}
   311|.md{display:none;position:fixed;inset:0;background:rgba(13,11,20,.85);align-items:center;justify-content:center;z-index:99}
   312|.mb{background:#1A1528;border:1px solid #2D2248;border-radius:16px;padding:32px;text-align:center;max-width:340px;width:90%}
   313|.mb h2{color:#E0DEF4;font-size:20px;margin-bottom:8px}
   314|.mb p{color:#908CAA;font-size:14px;line-height:1.5;margin-bottom:24px}
   315|.mb a{display:block;padding:12px;border-radius:10px;text-decoration:none;font-weight:600;font-size:15px;margin-bottom:12px}
   316|.mp{background:linear-gradient(135deg,#907AA9,#C4A7E7);color:#fff}
   317|.ms{background:#1A152E;color:#E0DEF4;border:1px solid #2D2248}
   318|.mb button{background:none;border:none;color:#6E6A86;cursor:pointer;font-size:13px;font-family:inherit}
   319|</style></head><body>
   320|<div class="card">
   321|<div class="title">Pass? or Yass? 🧐</div>
   322|<div class="sub">Discover Farcaster profiles. Swipe right for Yass, left for Pass.</div>
   323|<div class="btns"><a class="b bp" href="https://farcaster.xyz">Pass</a><a class="b by" href="https://farcaster.xyz">Yass</a></div>
   324|</div>
   325|<div class="ft"><a href="https://farcaster.xyz">Farcaster</a></div>
   326|</body></html>`;
   327|
   328|// ═══════════════════════════════════════════════════════════════════
   329|// SNAP HANDLER — uses ROUTE-BASED navigation (not query params)
   330|// ═══════════════════════════════════════════════════════════════════
   331|const app = new Hono();
   332|
   333|const snap: SnapFunction = async (ctx) => {
   334|  const base = snapBase(ctx.request);
   335|
   336|  // GET: always show gate
   337|  if (ctx.action.type === "get") {
   338|    return gatePage(base);
   339|  }
   340|
   341|  // POST: determine action from the registered route path
   342|  const fid = ctx.action.user.fid;
   343|  const path = new URL(ctx.request.url).pathname;
   344|
   345|  // Route: /gate-pass or /gate-yass
   346|  if (path === "/gate-pass") {
   347|    await setBehavioralTag(fid, "cautious");
   348|    return thanksPage();
   349|  }
   350|  if (path === "/gate-yass") {
   351|    await setBehavioralTag(fid, "adventurous");
   352|    return await handleGate(fid, base);
   353|  }
   354|
   355|  // Route: /swipe-pass?tid=X or /swipe-yass?tid=X
   356|  if (path.startsWith("/swipe-pass")) {
   357|    const tid = new URL(ctx.request.url).searchParams.get("tid");
   358|    if (tid) return await handleSwipe(fid, parseInt(tid), "pass", base);
   359|  }
   360|  if (path.startsWith("/swipe-yass")) {
   361|    const tid = new URL(ctx.request.url).searchParams.get("tid");
   362|    if (tid) return await handleSwipe(fid, parseInt(tid), "yass", base);
   363|  }
   364|
   365|  return gatePage(base);
   366|};
   367|
   368|// ─── Gate Handler ─────────────────────────────────────────────────
   369|async function handleGate(fid: number, base: string) {
   370|  const existing = await getQualification(fid);
   371|  if (existing?.qualified) return await showNext(fid, base);
   372|
   373|  const users = await fetchUsers([fid]);
   374|  if (!users.length) return rejectionPage();
   375|
   376|  const qual = qualifyUser(users[0]);
   377|  await setQualification(fid, qual);
   378|  if (!qual.qualified) return rejectionPage();
   379|
   380|  return await showNext(fid, base);
   381|}
   382|
   383|// ─── Swipe Handler ────────────────────────────────────────────────
   384|async function handleSwipe(swiperFid: number, targetFid: number, direction: string, base: string) {
   385|  const count = await getSwipeCount(swiperFid);
   386|  if (count >= DAILY_SWIPE_LIMIT) return dailyLimitPage();
   387|
   388|  const tag = (await getBehavioralTag(swiperFid)) ?? "unknown";
   389|  await recordSwipe(swiperFid, targetFid, direction, tag);
   390|  await incrementSwipe(swiperFid);
   391|
   392|  return await showNext(swiperFid, base);
   393|}
   394|
   395|// ─── Show Next Profile ────────────────────────────────────────────
   396|async function showNext(fid: number, base: string) {
   397|  const count = await getSwipeCount(fid);
   398|  if (count >= DAILY_SWIPE_LIMIT) return dailyLimitPage();
   399|
   400|  let pool = await getProfilePool(fid);
   401|  const swiped = await getSwipedFids(fid);
   402|  pool = pool.filter(p => !swiped.has(p.fid));
   403|
   404|  if (pool.length < 3) {
   405|    const newP = await buildProfilePool(fid);
   406|    const existing = new Set(pool.map(p => p.fid));
   407|    for (const p of newP) {
   408|      if (!existing.has(p.fid) && !swiped.has(p.fid)) {
   409|        pool.push(p);
   410|        existing.add(p.fid);
   411|      }
   412|    }
   413|    await setProfilePool(fid, pool);
   414|  }
   415|
   416|  if (pool.length === 0) return noMorePage();
   417|
   418|  const next = pool[0];
   419|  await setProfilePool(fid, pool.slice(1));
   420|  return profilePage(next, DAILY_SWIPE_LIMIT - count, base, pool.length - 1);
   421|}
   422|
   423|// ═══════════════════════════════════════════════════════════════════
   424|// SNAP UI PAGES
   425|// ═══════════════════════════════════════════════════════════════════
   426|const ACCENT = "purple" as const;
   427|
   428|function gatePage(base: string) {
   429|  return {
   430|    version: SPEC,
   431|    theme: { accent: ACCENT },
   432|    ui: {
   433|      root: "page",
   434|      elements: {
   435|        page: { type: "stack", props: {}, children: ["title", "sub", "sp", "btns"] },
   436|        title: { type: "text", props: { content: "Pass? or Yass?", size: "lg", weight: "bold", align: "center" } },
   437|        sub: { type: "text", props: { content: "Discover Farcaster profiles", size: "sm", align: "center" } },
   438|        sp: { type: "text", props: { content: " ", size: "sm" } },
   439|        btns: { type: "stack", props: { direction: "horizontal", gap: "md" }, children: ["bp", "by"] },
   440|        bp: {
   441|          type: "button", props: { label: "Pass", variant: "secondary" },
   442|          on: { press: { action: "submit", params: { target: `${base}/gate-pass` } } },
   443|        },
   444|        by: {
   445|          type: "button", props: { label: "Yass", variant: "primary" },
   446|          on: { press: { action: "submit", params: { target: `${base}/gate-yass` } } },
   447|        },
   448|      },
   449|    },
   450|  };
   451|}
   452|
   453|function profilePage(profile: Profile, remaining: number, base: string, poolCount: number) {
   454|  const bioText = profile.bio ? clamp(profile.bio, 100) : "";
   455|  const metaText = `${profile.followers.toLocaleString()} followers`;
   456|  const remText = poolCount > 1
   457|    ? `${poolCount} profiles left`
   458|    : poolCount === 1 ? "Last profile" : `${remaining} swipes left`;
   459|
   460|  const elements: Record<string, any> = {
   461|    page: {
   462|      type: "stack", props: {},
   463|      children: ["pfp", "name", ...(bioText ? ["bio"] : []), "meta", "sep", "rem", "btns"],
